     1→package com.rivvystudios.portal.controller;
     2→
     3→import com.rivvystudios.portal.config.LockoutProperties;
     4→import com.rivvystudios.portal.controller.dto.LoginRequest;
     5→import com.rivvystudios.portal.controller.dto.LoginResponse;
     6→import com.rivvystudios.portal.controller.dto.UserInfoResponse;
     7→import com.rivvystudios.portal.model.UserAccount;
     8→import com.rivvystudios.portal.model.enums.UserAccountStatus;
     9→import com.rivvystudios.portal.repository.UserAccountRepository;
    10→import jakarta.servlet.http.HttpServletRequest;
    11→import jakarta.servlet.http.HttpSession;
    12→import org.slf4j.Logger;
    13→import org.slf4j.LoggerFactory;
    14→import org.springframework.http.ResponseEntity;
    15→import org.springframework.security.authentication.AuthenticationManager;
    16→import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
    17→import org.springframework.security.core.Authentication;
    18→import org.springframework.security.core.AuthenticationException;
    19→import org.springframework.security.core.GrantedAuthority;
    20→import org.springframework.security.core.context.SecurityContext;
    21→import org.springframework.security.core.context.SecurityContextHolder;
    22→import org.springframework.security.crypto.password.PasswordEncoder;
    23→import org.springframework.security.web.context.HttpSessionSecurityContextRepository;
    24→import org.springframework.security.web.savedrequest.HttpSessionRequestCache;
    25→import org.springframework.security.web.savedrequest.SavedRequest;
    26→import org.springframework.web.bind.annotation.GetMapping;
    27→import org.springframework.web.bind.annotation.PostMapping;
    28→import org.springframework.web.bind.annotation.RequestBody;
    29→import org.springframework.web.bind.annotation.RequestMapping;
    30→import org.springframework.web.bind.annotation.RestController;
    31→
    32→import java.time.Instant;
    33→import java.util.Collection;
    34→import java.util.List;
    35→import java.util.Map;
    36→import java.util.Optional;
    37→import java.util.Set;
    38→import java.util.stream.Collectors;
    39→
    40→@RestController
    41→@RequestMapping("/api/auth")
    42→public class AuthController {
    43→
    44→    private static final Logger logger = LoggerFactory.getLogger(AuthController.class);
    45→    private static final int REMEMBER_ME_SECONDS = 180 * 24 * 60 * 60; // 180 days
    46→    private static final int DEFAULT_TIMEOUT_SECONDS = 1800; // 30 minutes
    47→    private static final String DUMMY_HASH = "$2a$10$dummyHashValueForTimingAttackPrevention1234567890";
    48→
    49→    private final AuthenticationManager authenticationManager;
    50→    private final UserAccountRepository userAccountRepository;
    51→    private final PasswordEncoder passwordEncoder;
    52→    private final LockoutProperties lockoutProperties;
    53→    private final HttpSessionRequestCache requestCache = new HttpSessionRequestCache();
    54→
    55→    public AuthController(AuthenticationManager authenticationManager,
    56→                          UserAccountRepository userAccountRepository,
    57→                          PasswordEncoder passwordEncoder,
    58→                          LockoutProperties lockoutProperties) {
    59→        this.authenticationManager = authenticationManager;
    60→        this.userAccountRepository = userAccountRepository;
    61→        this.passwordEncoder = passwordEncoder;
    62→        this.lockoutProperties = lockoutProperties;
    63→    }
    64→
    65→    @PostMapping("/login")
    66→    public ResponseEntity<?> login(@RequestBody LoginRequest loginRequest,
    67→                                   HttpServletRequest request) {
    68→        String email = loginRequest.getEmail();
    69→        String password = loginRequest.getPassword();
    70→
    71→        // Check if user exists
    72→        Optional<UserAccount> userAccountOpt = userAccountRepository.findByEmail(email);
    73→
    74→        if (userAccountOpt.isEmpty()) {
    75→            // Unknown email: perform dummy BCrypt operation for timing consistency
    76→            passwordEncoder.matches(password, DUMMY_HASH);
    77→            logger.warn("Failed login attempt for user {} - reason: unknown_email", email);
    78→            return ResponseEntity.status(401)
    79→                    .body(Map.of("error", "Invalid email or password"));
    80→        }
    81→
    82→        UserAccount userAccount = userAccountOpt.get();
    83→        Instant now = Instant.now();
    84→
    85→        // Check if account is locked
    86→        if (userAccount.getLockedUntil() != null) {
    87→            if (userAccount.getLockedUntil().isAfter(now)) {
    88→                // Account is still locked
    89→                logger.warn("Failed login attempt for user {} - reason: account_locked", userAccount.getId());
    90→                return ResponseEntity.status(401)
    91→                        .body(Map.of("error", "Invalid email or password"));
    92→            } else {
    93→                // Lockout has expired - clear lockout fields
    94→                logger.info("Account lockout expired for user {} at {}", userAccount.getId(), userAccount.getLockedUntil());
    95→                clearLockoutFields(userAccount);
    96→                userAccountRepository.save(userAccount);
    97→            }
    98→        }
    99→
   100→        // Check for PENDING status (invited users)
   101→        if (userAccount.getStatus() == UserAccountStatus.PENDING) {
   102→            logger.warn("Failed login attempt for user {} - reason: invited_account", userAccount.getId());
   103→            return ResponseEntity.status(401)
   104→                    .body(Map.of("error", "Invalid email or password"));
   105→        }
   106→
   107→        // Check for INACTIVE/SUSPENDED status (disabled users)
   108→        if (userAccount.getStatus() == UserAccountStatus.INACTIVE ||
   109→            userAccount.getStatus() == UserAccountStatus.SUSPENDED) {
   110→            // Check if password is correct
   111→            if (passwordEncoder.matches(password, userAccount.getPasswordHash())) {
   112→                // Correct password - reveal disabled message
   113→                logger.warn("Failed login attempt for user {} - reason: disabled_account (correct password)", userAccount.getId());
   114→                return ResponseEntity.status(401)
   115→                        .body(Map.of("error", "Your account has been disabled. Please contact support."));
   116→            } else {
   117→                // Incorrect password - generic error
   118→                logger.warn("Failed login attempt for user {} - reason: disabled_account (incorrect password)", userAccount.getId());
   119→                return ResponseEntity.status(401)
   120→                        .body(Map.of("error", "Invalid email or password"));
   121→            }
   122→        }
   123→
   124→        // At this point, user is ACTIVE and not locked - attempt authentication
   125→        try {
   126→            Authentication authentication = authenticationManager.authenticate(
   127→                    new UsernamePasswordAuthenticationToken(email, password)
   128→            );
   129→
   130→            // Authentication successful - clear lockout counters and update last login
   131→            if (userAccount.getFailedAttemptsCount() > 0) {
   132→                logger.info("Successful login for user {} - lockout counters reset", userAccount.getId());
   133→            }
   134→            clearLockoutFields(userAccount);
   135→            userAccount.setLastLoginAt(now);
   136→            userAccountRepository.save(userAccount);
   137→
   138→            // Create SecurityContext and store in session
   139→            SecurityContext securityContext = SecurityContextHolder.createEmptyContext();
   140→            securityContext.setAuthentication(authentication);
   141→            SecurityContextHolder.setContext(securityContext);
   142→
   143→            HttpSession session = request.getSession(true);
   144→            session.setAttribute(
   145→                    HttpSessionSecurityContextRepository.SPRING_SECURITY_CONTEXT_KEY,
   146→                    securityContext
   147→            );
   148→
   149→            // Configure session timeout based on rememberMe
   150→            if (loginRequest.isRememberMe()) {
   151→                session.setMaxInactiveInterval(REMEMBER_ME_SECONDS);
   152→            } else {
   153→                session.setMaxInactiveInterval(DEFAULT_TIMEOUT_SECONDS);
   154→            }
   155→
   156→            // Compute redirect URL
   157→            String redirectUrl = computeRedirectUrl(request, authentication);
   158→
   159→            // Build role code list (strip ROLE_ prefix)
   160→            List<String> roles = authentication.getAuthorities().stream()
   161→                    .map(GrantedAuthority::getAuthority)
   162→                    .filter(a -> a.startsWith("ROLE_"))
   163→                    .map(a -> a.substring(5))
   164→                    .collect(Collectors.toList());
   165→
   166→            LoginResponse response = new LoginResponse(
   167→                    redirectUrl,
   168→                    userAccount.getEmail(),
   169→                    userAccount.getFirstName(),
   170→                    userAccount.getLastName(),
   171→                    roles
   172→            );
   173→
   174→            return ResponseEntity.ok(response);
   175→
   176→        } catch (AuthenticationException ex) {
   177→            // Authentication failed - handle failed attempt tracking
   178→            handleFailedAttempt(userAccount, now);
   179→            logger.warn("Failed login attempt for user {} - reason: wrong_password", userAccount.getId());
   180→            return ResponseEntity.status(401)
   181→                    .body(Map.of("error", "Invalid email or password"));
   182→        }
   183→    }
   184→
   185→    private void handleFailedAttempt(UserAccount userAccount, Instant now) {
   186→        int windowMinutes = lockoutProperties.getWindowMinutes();
   187→        Instant windowStart = now.minusSeconds(windowMinutes * 60L);
   188→
   189→        // Check if first failed attempt is outside the window
   190→        if (userAccount.getFirstFailedAttemptAt() == null ||
   191→            userAccount.getFirstFailedAttemptAt().isBefore(windowStart)) {
   192→            // Reset window
   193→            userAccount.setFirstFailedAttemptAt(now);
   194→            userAccount.setFailedAttemptsCount(1);
   195→        } else {
   196→            // Increment within window
   197→            userAccount.setFailedAttemptsCount(userAccount.getFailedAttemptsCount() + 1);
   198→        }
   199→
   200→        userAccount.setLastFailedAttemptAt(now);
   201→
   202→        // Check if threshold reached
   203→        if (userAccount.getFailedAttemptsCount() >= lockoutProperties.getThreshold()) {
   204→            int durationMinutes = lockoutProperties.getDurationMinutes();
   205→            Instant lockedUntil = now.plusSeconds(durationMinutes * 60L);
   206→            userAccount.setLockedUntil(lockedUntil);
   207→            logger.warn("Account locked for user {} - threshold {} reached", userAccount.getId(), lockoutProperties.getThreshold());
   208→        }
   209→
   210→        userAccountRepository.save(userAccount);
   211→    }
   212→
   213→    private void clearLockoutFields(UserAccount userAccount) {
   214→        userAccount.setFailedAttemptsCount(0);
   215→        userAccount.setFirstFailedAttemptAt(null);
   216→        userAccount.setLastFailedAttemptAt(null);
   217→        userAccount.setLockedUntil(null);
   218→    }
   219→
   220→    @GetMapping("/me")
   221→    public ResponseEntity<?> me() {
   222→        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
   223→
   224→        if (authentication == null || !authentication.isAuthenticated()
   225→                || "anonymousUser".equals(authentication.getPrincipal())) {
   226→            return ResponseEntity.status(401)
   227→                    .body(Map.of("error", "Unauthorized"));
   228→        }
   229→
   230→        String email = authentication.getName();
   231→        UserAccount userAccount = userAccountRepository.findByEmail(email).orElse(null);
   232→
   233→        List<String> roles = authentication.getAuthorities().stream()
   234→                .map(GrantedAuthority::getAuthority)
   235→                .filter(a -> a.startsWith("ROLE_"))
   236→                .map(a -> a.substring(5))
   237→                .collect(Collectors.toList());
   238→
   239→        UserInfoResponse response = new UserInfoResponse(
   240→                email,
   241→                userAccount != null ? userAccount.getFirstName() : null,
   242→                userAccount != null ? userAccount.getLastName() : null,
   243→                roles
